const input = $input.first().json;
const { whatsapp, estado_motivo, resumen } = input;

if (!whatsapp) {
  return [{ json: { error: 'whatsapp es requerido' } }];
}

const updateFields = [];
if (estado_motivo) updateFields.push(`estado_motivo = '${estado_motivo.replace(/'/g, "''")}' `);
if (resumen) updateFields.push(`resumen = '${resumen.replace(/'/g, "''")}' `);
updateFields.push(`updated_at = NOW()`);

const query = `UPDATE leads
SET ${updateFields.join(', ')}
WHERE whatsapp = '${whatsapp}'
RETURNING *;`;

return [{
  json: {
    query,
    whatsapp,
    estado_motivo,
    resumen
  }
}];

const result = $input.first().json;
const data = result.map(row => row.json);

return [{
  json: {
    success: true,
    message: `Lead actualizado`,
    lead: data[0] || null
  }
}];
